/**
 * App.jsx - InSight Hold Melt Dashboard
 *
 * Main dashboard component for visualizing PERC registration hold placement
 * and clearance patterns across academic years at Champlain College.
 *
 * ARCHITECTURE OVERVIEW:
 *   - Raw hold records are embedded as JSON (generated by scripts/build-data.py)
 *   - All melt-curve computation happens at runtime via computeAll()
 *   - The "delay" setting shifts end dates forward to account for backdating
 *   - All class standings (FY, SO, JR, SR, ALUM) included in melt curves
 *   - Class breakdown (FY/SO/JR) only used for current cohort where data is accurate
 *   - Hold recurrence tracked via student IDs across restriction codes
 *   - Prior-year average recalculates reactively when cohort toggles change
 *   - Date math uses native JavaScript Date objects (handles leap years)
 *
 * DATA FLOW:
 *   CSV (PERC export) -> build-data.py -> holds.json -> RAW_HOLDS -> computeAll()
 *   -> cohorts{} with melt curves -> Recharts visualization
 *
 * KEY SETTINGS:
 *   - Hold Release Delay: Compensates for the practice of backdating hold
 *     removal by N days. Default is 1 (a hold logged as removed on March 27
 *     was actually released on March 28).
 *   - Font Size: Scales all text proportionally (0.85x / 1.0x / 1.15x)
 */

import { useState, useMemo, useCallback, useRef, useEffect } from "react";
import {
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  BarChart, Bar, ReferenceLine, Area, AreaChart, ComposedChart
} from "recharts";


// ═══════════════════════════════════════════════════════════════════════
// RAW DATA
// Imported from src/data/holds.json, generated by scripts/build-data.py.
// Workflow: drop CSV in data/ -> npm run build-data -> Vite hot-reloads.
// Each record: { r: restriction code, s: start date, e: end date, c: class }
// Empty "e" means the hold is still active (student hasn't cleared).
// ═══════════════════════════════════════════════════════════════════════
import holdsData from "./data/holds.json";
const RAW_HOLDS = holdsData.holds;

/**
 * Maps restriction codes to academic year display labels.
 * Add new entries here as new hold cycles begin.
 */
const YEAR_LABELS = {
  "INS21": "20-21",
  "INS23": "22-23",
  "INS24": "23-24",
  "INS25": "24-25",
  "INS26": "25-26",
};


